            $sql = "INSERT INTO testparameters (ParameterName, StandardID, MinLimit, MaxLimit, Method, "
                    . "Vital, Category, MRL, MRLUnit, UnitOfMeasure) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)";
            
            
            $stmt = $conn->prepare($sql);
            if (!$stmt) {
                $errormessage[] = ["success" => false, "message" => $conn->error];
                continue;
            }

            $stmt->bind_param(
                'siddsisdss',
                trim($row['Parameter']),
                trim($row['sampletypeid']),
                trim($row['MinimumLimit']),
                trim($row['MaximumLimit']),
                trim($row['Method']),
                trim($row['vital']),
                trim($row['category']=='1'?'chemical':'microbiological'),
                trim('0'),
                trim(''),
                trim($row['Units'])
            );

            if ($stmt->execute()) {
                $insertCount++;
            } else {
                $errormessage[] = ["success" => false, "message" => $stmt->error];
            }
